class Publisher(RabbitMQClient):
    def publish_task(self, task_name: str, payload: dict):
        if not self.channel or self.channel.is_closed:
            self.connect()

        message = TaskMessage(
            task_id=str(uuid.uuid4()),
            task_name=task_name,
            payload=payload,
            created_at=time.time(),
        )

        self.channel.basic_publish(
            exchange="",
            routing_key=TASK_QUEUE,
            body=message.to_json(),
            properties=pika.BasicProperties(
                delivery_mode=2,
                content_type="application/json",
            ),
        )
        print(f"Published task: {message.task_id} ({message.task_name})")


class Consumer(RabbitMQClient):
    def __init__(self, host: str = RABBITMQ_HOST, port: int = RABBITMQ_PORT, prefetch_count: int = 1):
        super().__init__(host, port)
        self.prefetch_count = prefetch_count
        self._stop_event = threading.Event()

    def process_task(self, task: TaskMessage):
        print(f"Processing task: {task.task_id} ({task.task_name}) payload={task.payload}")
        duration = task.payload.get("duration", 1)
        try:
            duration = float(duration)
        except Exception:
            duration = 1
        time.sleep(max(0, duration))
        print(f"Completed task: {task.task_id}")

    def _callback(self, ch, method, properties, body):
        try:
            task = TaskMessage.from_json(body)
            self.process_task(task)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            print(f"Error processing message: {e}", file=sys.stderr)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    def start(self):
        if not self.channel or self.channel.is_closed:
            self.connect()

        self.channel.basic_qos(prefetch_count=self.prefetch_count)
        self.channel.basic_consume(queue=TASK_QUEUE, on_message_callback=self._callback)

